export function ChartsRotationGrid(props: ChartsRotationGridProps) {
  const { store } = useChartsContext<[UseChartPolarAxisSignature]>();
  const { axis, innerRadius, outerRadius, classes } = props;
  const { cx, cy } = store.use(selectorChartPolarCenter);

  const { scale, tickNumber, tickInterval, tickSpacing } = axis;

  const ticks = useTicks({
    scale,
    tickNumber,
    tickInterval,
    tickSpacing,
    direction: 'rotation',
  });

  return (
    <React.Fragment>
      {ticks.map(({ value, offset }) => {
        const angle = offset - Math.PI / 2;

        const dx = Math.cos(angle);
        const dy = Math.sin(angle);

        const x1 = cx + innerRadius * dx;
        const y1 = cy + innerRadius * dy;
        const x2 = cx + outerRadius * dx;
        const y2 = cy + outerRadius * dy;
        return (
          <GridLine
            key={`rotation-${value?.getTime?.() ?? value}`}
            x1={x1}
            y1={y1}
            x2={x2}
            y2={y2}
            className={classes.rotationLine}
          />
        );
      })}
    </React.Fragment>
  );
}

function AxisLine(axisLineProps: {
  x: number;
  y: number;
  width: number;
  height: number;
  orientation: Orientation;
  mirror: boolean;
  axisLine: boolean | SVGProps<SVGLineElement>;
  otherSvgProps: SVGProps<SVGLineElement> | null;
}) {
  const { x, y, width, height, orientation, mirror, axisLine, otherSvgProps } = axisLineProps;

  if (!axisLine) {
    return null;
  }

  let props: SVGProps<SVGLineElement> = {
    ...otherSvgProps,
    ...svgPropertiesNoEvents(axisLine),
    fill: 'none',
  };

  if (orientation === 'top' || orientation === 'bottom') {
    const needHeight = +((orientation === 'top' && !mirror) || (orientation === 'bottom' && mirror));
    props = {
      ...props,
      x1: x,
      y1: y + needHeight * height,
      x2: x + width,
      y2: y + needHeight * height,
    };
  } else {
    const needWidth = +((orientation === 'left' && !mirror) || (orientation === 'right' && mirror));
    props = {
      ...props,
      x1: x + needWidth * width,
      y1: y,
      x2: x + needWidth * width,
      y2: y + height,
    };
  }

  return <line {...props} className={clsx('recharts-cartesian-axis-line', get(axisLine, 'className'))} />;
}

